11	// TestAttempt_WrapsLegacyExecutor verifies that Attempt delegates to the
12	// injected ExecuteBeadExecutor and converts its ExecuteBeadReport to a
13	// try.Outcome via the C1 ToOutcome adapter.
14	func TestAttempt_WrapsLegacyExecutor(t *testing.T) {
15		t.Run("merged report becomes DispositionMerged", func(t *testing.T) {
16			var gotBead string
17			stub := agent.ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (agent.ExecuteBeadReport, error) {
18				gotBead = beadID
19				return agent.ExecuteBeadReport{
20					BeadID:     "ddx-aaaaaaaa",
21					AttemptID:  "att-1",
22					BaseRev:    "deadbeef",
23					ResultRev:  "cafebabe",
24					SessionID:  "sess-xyz",
25					Status:     agent.ExecuteBeadStatusSuccess,
26					CostUSD:    0.42,
27					DurationMS: 1234,
28				}, nil
29			})
30			out, err := Attempt(context.Background(), nil, "ddx-aaaaaaaa", AttemptOpts{Executor: stub})
31			if err != nil {
32				t.Fatalf("Attempt err = %v, want nil", err)
33			}
34			if gotBead != "ddx-aaaaaaaa" {
35				t.Fatalf("stub got beadID = %q, want %q", gotBead, "ddx-aaaaaaaa")
36			}
37			if out.Disposition != DispositionMerged {
38				t.Errorf("Disposition = %v, want %v", out.Disposition, DispositionMerged)
39			}
40			if out.BeadID != "ddx-aaaaaaaa" || out.AttemptID != "att-1" {
41				t.Errorf("Outcome ids = (%q,%q), want (ddx-aaaaaaaa, att-1)", out.BeadID, out.AttemptID)
42			}
43			if out.BaseRev != "deadbeef" || out.ResultRev != "cafebabe" {
44				t.Errorf("Outcome revs = (%q,%q), want (deadbeef, cafebabe)", out.BaseRev, out.ResultRev)
45			}
46			if out.SessionID != "sess-xyz" || out.CostUSD != 0.42 || out.DurationMS != 1234 {
47				t.Errorf("Outcome telemetry = (%q,%v,%v), want (sess-xyz, 0.42, 1234)", out.SessionID, out.CostUSD, out.DurationMS)
48			}
49		})
50	
51		t.Run("preserved-needs-review report becomes DispositionPark/needs_review", func(t *testing.T) {
52			stub := agent.ExecuteBeadExecutorFunc(func(_ context.Context, _ string) (agent.ExecuteBeadReport, error) {
53				return agent.ExecuteBeadReport{
54					BeadID: "ddx-bbbbbbbb",
55					Status: agent.ExecuteBeadStatusPreservedNeedsReview,
