60				t.Fatalf("Attempt err = %v, want nil", err)
61			}
62			if out.Disposition != DispositionPark {
63				t.Errorf("Disposition = %v, want %v", out.Disposition, DispositionPark)
64			}
65			if out.ParkReason != ParkReasonNeedsReview {
66				t.Errorf("ParkReason = %q, want %q", out.ParkReason, ParkReasonNeedsReview)
67			}
68		})
69	
70		t.Run("executor error is propagated; outcome carries beadID", func(t *testing.T) {
71			wantErr := errors.New("boom")
72			stub := agent.ExecuteBeadExecutorFunc(func(_ context.Context, _ string) (agent.ExecuteBeadReport, error) {
73				return agent.ExecuteBeadReport{}, wantErr
74			})
75			out, err := Attempt(context.Background(), nil, "ddx-cccccccc", AttemptOpts{Executor: stub})
76			if !errors.Is(err, wantErr) {
77				t.Fatalf("Attempt err = %v, want %v", err, wantErr)
78			}
