43	func TestOutcome_RoundTripsExecuteBeadReport(t *testing.T) {
44		base := Outcome{
45			BeadID:     "ddx-aaaaaaaa",
46			AttemptID:  "att-1",
47			BaseRev:    "deadbeefdeadbeef",
48			ResultRev:  "cafebabecafebabe",
49			SessionID:  "sess-xyz",
50			DurationMS: 4321,
51			CostUSD:    0.1234,
52			Cooldown:   90 * time.Second,
53		}
54	
55		cases := []struct {
56			name string
57			o    Outcome
58		}{
59			{"merged", with(base, DispositionMerged, "")},
60			{"already_done", with(base, DispositionAlreadyDone, "")},
61			{"retry", with(base, DispositionRetry, "")},
62			{"needs_human", with(base, DispositionNeedsHuman, "")},
63			{"loop_error", with(base, DispositionLoopError, "")},
64			{"park_needs_review", with(base, DispositionPark, ParkReasonNeedsReview)},
65			{"park_decomposition", with(base, DispositionPark, ParkReasonDecomposition)},
66			{"park_push_failed", with(base, DispositionPark, ParkReasonPushFailed)},
67			{"park_push_conflict", with(base, DispositionPark, ParkReasonPushConflict)},
68			{"park_cost_cap", with(base, DispositionPark, ParkReasonCostCap)},
69			{"park_loop_error", with(base, DispositionPark, ParkReasonLoopError)},
70			{"park_no_changes_unverified", with(base, DispositionPark, ParkReasonNoChangesUnverified)},
71			{"park_no_changes_unjustified", with(base, DispositionPark, ParkReasonNoChangesUnjustified)},
72			{"park_rate_limit", with(base, DispositionPark, ParkReasonRateLimitBudgetExhausted)},
73			{"park_quota_paused", with(base, DispositionPark, ParkReasonQuotaPaused)},
74			{"park_lock_contention", with(base, DispositionPark, ParkReasonLockContention)},
75		}
